def _changed_params(estimator):
    """Return dict (param_name: value) of parameters that were given to
    estimator with non-default values."""

    import inspect
    try:
        import numpy as _np
    except Exception:
        _np = None

    def _param_equals(a, b):
        """Robust equality for parameter default comparison; returns bool.

        - Returns False if either side is inspect._empty (no default).
        - Uses elementwise comparison where appropriate and reduces ndarray
          results to a single boolean via .all().
        - Falls back to bool(eq) for Python scalars and numpy scalars.
        - On any exception during comparison, returns False (treat as not
          equal).
        """
        # If either is the sentinel meaning "no default", they are not equal
        if a is inspect._empty or b is inspect._empty:
            return False
        try:
            eq = a == b
        except Exception:
            # e.g., comparison not supported between types
            return False
        # If eq is a numpy ndarray, reduce elementwise comparison
        if _np is not None and isinstance(eq, _np.ndarray):
            try:
                return bool(eq.all())
            except Exception:
                return False
        # For numpy scalar types or Python bool-like results, coerce to bool
        try:
            return bool(eq)
        except Exception:
            return False

    params = estimator.get_params(deep=False)
    filtered_params = {}
    init_func = getattr(estimator.__init__, 'deprecated_original',
                        estimator.__init__)
    init_params = signature(init_func).parameters
    init_params = {name: param.default for name, param in init_params.items()}

    for k, v in params.items():
        default = init_params.get(k, inspect._empty)
        if default is inspect._empty:
            # No default provided in the signature: conservatively consider as changed
            filtered_params[k] = v
            continue
        # Preserve existing NaN special-case: if both are NaN, treat as equal
        if (not _param_equals(v, default) and
                not (is_scalar_nan(default) and is_scalar_nan(v))):
            filtered_params[k] = v
    return filtered_params

