def _convert_pandas_nullable(y):
    """If ``y`` is a pandas ExtensionArray / Series with a nullable dtype,
    convert it to an appropriate NumPy ndarray to avoid object-dtype/extension
    semantics that confuse dtype.kind checks.

    This helper is best-effort: it returns the original ``y`` if pandas is not
    available or if the input is not a pandas ExtensionDtype-backed object.

    Conversion policy (mirrors validation.check_array pattern):
    - nullable integer dtype with missing values -> np.float64 (np.nan for NA)
    - nullable integer dtype without missing values -> np.int64
    - float extension dtype -> np.float64
    - boolean extension dtype without missing values -> bool
    - boolean extension dtype with missing values -> object (so pd.NA is preserved as an object)
    """
    try:
        import pandas as pd
        from pandas.api.types import (
            is_extension_array_dtype,
            is_integer_dtype,
            is_float_dtype,
            is_bool_dtype,
        )
    except Exception:
        # pandas not available or import failed: do nothing
        return y

    # Only handle objects that have a dtype (e.g. Series, Index, ExtensionArray)
    if not hasattr(y, "dtype"):
        return y

    try:
        pd_dtype = y.dtype
    except Exception:
        return y

    try:
        if not is_extension_array_dtype(pd_dtype):
            return y
    except Exception:
        # Any unexpected pandas behavior: be conservative and return original
        return y

    # Determine presence of NA values if possible
    hasna = getattr(y, "hasnans", None)
    if hasna is None:
        try:
            # pd.isna works for Series and ExtensionArray
            hasna = pd.isna(y).any()
        except Exception:
            hasna = False

    # Prefer to use to_numpy when available to respect pandas semantics
    to_numpy = getattr(y, "to_numpy", None)

    try:
        if is_bool_dtype(pd_dtype):
            if hasna:
                # preserve missingness as object dtype so pd.NA stays representable
                return to_numpy(dtype=object) if to_numpy is not None else np.asarray(y, dtype=object)
            else:
                return to_numpy(dtype=bool) if to_numpy is not None else np.asarray(y, dtype=bool)
        elif is_integer_dtype(pd_dtype):
            if hasna:
                # map nullable ints-with-NA to float64 (np.nan) to avoid object dtype
                return to_numpy(dtype=np.float64) if to_numpy is not None else np.asarray(y, dtype=np.float64)
            else:
                return to_numpy(dtype=np.int64) if to_numpy is not None else np.asarray(y, dtype=np.int64)
        elif is_float_dtype(pd_dtype):
            return to_numpy(dtype=np.float64) if to_numpy is not None else np.asarray(y, dtype=np.float64)
    except Exception:
        # If conversion fails for any reason, fall back to original object
        return y

    # Default fallback: convert via to_numpy() or np.asarray()
    return to_numpy() if to_numpy is not None else np.asarray(y)

